          16
        ]
      }
    ],
    "roles": [
      {
        "source": "李源祥",
        "target": "Lee Yuen Cheung",
        "role": "Group Chief Executive and President"
      }
    ],
    "terms": [],
    "style_rules": [
      "Use US$ for U.S. dollar amounts.",
      "Keep listed-company annual report disclosure tone formal and publishable.",
      "Do not change numbers, percentages, years, named entities or financial metric values.",
      "Use established financial abbreviations for table labels when provided.",
      "Keep row and column semantics unchanged.",
      "Use n/m for 無意義."
    ]
  },
  "current_unit": {
    "page_no": 15,
    "unit_id": "p15_g07",
    "unit_mode": "semantic_group",
    "slot_count": 3,
    "source_text": "友邦保險參與氣候相關財務披露工作小組(Task Force on Climate-related Financial Disclosures)，這個全球組\n織致力就氣候變化影響建立一個自願和一致的披露框架。我們繼續重申對有關建議的承諾，在2020年與我們投資\n組合內逾1,400家公司，以及超過30名外部投資經理聯繫，致力影響其如何管理氣候變化風險及應對氣候問題。",
    "current_translation": "AIA participates in the Task Force on Climate-related Financial Disclosures, a global organization dedicated to establishing a voluntary and consistent disclosure framework on the impacts of climate change. We continue to reaffirm our commitment to its recommendations, and in 2020 engaged with over 1,400 companies in our investment portfolio and more than 30 external investment managers to influence how they manage climate change risks and address climate-related issues."
  },
  "output_format": {
    "translations": [
      {
        "unit_id": "p15_g07",
        "translation": "<更紧凑译文>"
      }
    ]
  }
}

